declare module '*.md' {
  const content: string
  export default content
}

declare module '*.pdf' {
  const content: ArrayBuffer
  export default content
}

declare module '*.svg' {
  const content: string
  export default content
}

declare module '*.css' {
  const content: string
  export default content
}

declare module '*.png' {
  const content: ArrayBuffer
  export default content
}
